using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.Name, Price = e.Price, Quantity = e.Qty }).ToList();

    // ── CreateOrder ─────────────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 5.50m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(36.50m, order.Total); // 10*2 + 5.5*3
        Assert.AreEqual(2, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_SetsTotal()
    {
        // Arrange
        var items = CreateItems(("Book", 12.99m, 1));

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert
        Assert.AreEqual(12.99m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems(("Item", 1m, 1));

        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // ── GetOrder ────────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var created = _sut.CreateOrder("cust-1", CreateItems(("Pen", 2m, 5)));

        // Act
        var found = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
        Assert.AreEqual(10m, found.Total);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    // ── GetOrdersByCustomer ─────────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        // Arrange
        _sut.CreateOrder("cust-A", CreateItems(("X", 1m, 1)));
        _sut.CreateOrder("cust-A", CreateItems(("Y", 2m, 1)));
        _sut.CreateOrder("cust-B", CreateItems(("Z", 3m, 1)));

        // Act
        var ordersA = _sut.GetOrdersByCustomer("cust-A");
        var ordersB = _sut.GetOrdersByCustomer("cust-B");

        // Assert
        Assert.AreEqual(2, ordersA.Count);
        Assert.AreEqual(1, ordersB.Count);
        Assert.IsTrue(ordersA.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        // Act
        var orders = _sut.GetOrdersByCustomer("nobody");

        // Assert
        Assert.AreEqual(0, orders.Count);
    }
}

